import React from "react";
import { useNavigate } from "react-router-dom";

function BloodBankPage() {
  const navigate = useNavigate();

  return (
    <div className="page">
      <button className="back-icon" onClick={() => navigate("/")} aria-label="Back">←</button>

      <h2>Blood Bank Services</h2>
      <p>
        Search and connect with nearby blood banks, donors, and availability in real time.
      </p>
    </div>
  );
}

export default BloodBankPage;
